{"path": "/tmp/sv-974bd94d350c488783f4ddea69e54413/ContosoUniversity.Tests/Services/NotificationServiceTests.cs", "file_text": "using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any leftover notifications from other tests (static queue)
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            // Drain after tests too
            while (_service.ReceiveNotification() != null) { }
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithDisplayName_IncludesNameInMessage()
        {
            _service.SendNotification("Course", "42", "Chemistry", EntityOperation.CREATE, "admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("Chemistry", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "99", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("99", notification.Message);
        }

        [Fact]
        public void SendNotification_CreateOperation_GeneratesCorrectMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Contains("created", notification!.Message);
            Assert.Contains("John Doe", notification.Message);
        }

        [Fact]
        public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
        {
            _service.SendNotification("Course", "1", "Chemistry", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.Contains("updated", notification!.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
        {
            _service.SendNotification("Department", "1", "Engineering", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();
            Assert.Contains("deleted", notification!.Message);
        }

        [Fact]
        public void SendNotification_DefaultUserName_IsSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("System", notification!.CreatedBy);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now;

            var notification = _service.ReceiveNotification();
            Assert.InRange(notification!.CreatedAt, before, after);
        }

        [Fact]
        public void ReceiveNotification_ReturnsNull_WhenQueueIsEmpty()
        {
            var result = _service.ReceiveNotification();
            Assert.Null(result);
        }

        [Fact]
        public void ReceiveNotification_ReturnsFIFO()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            _service.SendNotification("Course", "2", EntityOperation.UPDATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.Equal("Student", first!.EntityType);
            Assert.Equal("Course", second!.EntityType);
        }

        [Fact]
        public void ReceiveNotification_RemovesFromQueue()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var first = _service.ReceiveNotification();
            Assert.NotNull(first);

            var second = _service.ReceiveNotification();
            Assert.Null(second);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            var exception = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_OverloadWithoutDisplayName_Works()
        {
            _service.SendNotification("Instructor", "5", EntityOperation.UPDATE, "teacher");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Instructor", notification.EntityType);
            Assert.Equal("5", notification.EntityId);
            Assert.Equal("UPDATE", notification.Operation);
            Assert.Equal("teacher", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_MultipleNotifications_AllEnqueued()
        {
            for (int i = 0; i < 5; i++)
            {
                _service.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }

            int count = 0;
            while (_service.ReceiveNotification() != null) count++;
            Assert.Equal(5, count);
        }
    }
}
"}

{"path": "/tmp/sv-974bd94d350c488783f4ddea69e54413/ContosoUniversity.Tests/PaginatedListTests.cs", "file_text": "using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndex()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 2, 3);

            Assert.Equal(2, list.PageIndex);
        }

        [Fact]
        public void Constructor_CalculatesTotalPages()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 1, 3);

            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
        }

        [Fact]
        public void Constructor_TotalPages_ExactDivision()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 9, 1, 3);

            Assert.Equal(3, list.TotalPages);
        }

        [Fact]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<string> { "a", "b", "c" };
            var list = new PaginatedList<string>(items, 10, 1, 5);

            Assert.Equal(3, list.Count);
            Assert.Contains("a", list);
            Assert.Contains("b", list);
            Assert.Contains("c", list);
        }

        [Fact]
        public void HasPreviousPage_ReturnsFalse_OnFirstPage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_ReturnsTrue_OnSecondPage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5);
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_ReturnsTrue_WhenNotOnLastPage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);
            Assert.True(list.HasNextPage); // TotalPages = 2, PageIndex = 1
        }

        [Fact]
        public void HasNextPage_ReturnsFalse_OnLastPage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5);
            Assert.False(list.HasNextPage); // TotalPages = 2, PageIndex = 2
        }

        [Fact]
        public void HasNextPage_ReturnsFalse_WhenSinglePage()
        {
            var list = new PaginatedList<int>(new List<int> { 1, 2 }, 2, 1, 5);
            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var page1 = PaginatedList<int>.Create(source, 1, 5);
            Assert.Equal(5, page1.Count);
            Assert.Equal(1, page1.First());
            Assert.Equal(5, page1.Last());
            Assert.Equal(4, page1.TotalPages);

            var page2 = PaginatedList<int>.Create(source, 2, 5);
            Assert.Equal(5, page2.Count);
            Assert.Equal(6, page2.First());
            Assert.Equal(10, page2.Last());
        }

        [Fact]
        public void Create_LastPage_HasRemainingItems()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();

            var page3 = PaginatedList<int>.Create(source, 3, 5);
            Assert.Equal(2, page3.Count);
            Assert.Equal(11, page3.First());
            Assert.Equal(12, page3.Last());
        }

        [Fact]
        public void Create_SinglePage_AllItems()
        {
            var source = Enumerable.Range(1, 3).AsQueryable();

            var page = PaginatedList<int>.Create(source, 1, 10);
            Assert.Equal(3, page.Count);
            Assert.Equal(1, page.TotalPages);
            Assert.False(page.HasPreviousPage);
            Assert.False(page.HasNextPage);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var page = PaginatedList<int>.Create(source, 1, 10);
            Assert.Empty(page);
            Assert.Equal(0, page.TotalPages);
        }
    }
}
"}

