using ContosoUniversity.Models;
using System;

namespace ContosoUniversity.Tests.Models
{
    public class PersonTests
    {
        [Fact]
        public void FullName_ReturnsLastNameCommaFirstName()
        {
            var student = new Student { LastName = "Smith", FirstMidName = "John" };
            Assert.Equal("Smith, John", student.FullName);
        }

        [Fact]
        public void Student_InheritsFromPerson()
        {
            var student = new Student();
            Assert.IsAssignableFrom<Person>(student);
        }

        [Fact]
        public void Instructor_InheritsFromPerson()
        {
            var instructor = new Instructor();
            Assert.IsAssignableFrom<Person>(instructor);
        }

        [Fact]
        public void Student_HasEnrollmentDate()
        {
            var date = new DateTime(2020, 9, 1);
            var student = new Student { EnrollmentDate = date };
            Assert.Equal(date, student.EnrollmentDate);
        }

        [Fact]
        public void Instructor_HasHireDate()
        {
            var date = new DateTime(2020, 1, 15);
            var instructor = new Instructor { HireDate = date };
            Assert.Equal(date, instructor.HireDate);
        }

        [Fact]
        public void Student_EnrollmentsCollection_DefaultsToNull()
        {
            var student = new Student();
            Assert.Null(student.Enrollments);
        }

        [Fact]
        public void Instructor_CourseAssignmentsCollection_DefaultsToNull()
        {
            var instructor = new Instructor();
            Assert.Null(instructor.CourseAssignments);
        }

        [Fact]
        public void Instructor_OfficeAssignment_DefaultsToNull()
        {
            var instructor = new Instructor();
            Assert.Null(instructor.OfficeAssignment);
        }
    }

    public class CourseModelTests
    {
        [Fact]
        public void Course_Properties_SetCorrectly()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };

            Assert.Equal(1050, course.CourseID);
            Assert.Equal("Chemistry", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
        }

        [Fact]
        public void Course_TeachingMaterialImagePath_DefaultsToNull()
        {
            var course = new Course();
            Assert.Null(course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Course_NavigationProperties_DefaultToNull()
        {
            var course = new Course();
            Assert.Null(course.Department);
            Assert.Null(course.Enrollments);
            Assert.Null(course.CourseAssignments);
        }
    }

    public class DepartmentModelTests
    {
        [Fact]
        public void Department_Properties_SetCorrectly()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 5
            };

            Assert.Equal(1, dept.DepartmentID);
            Assert.Equal("Engineering", dept.Name);
            Assert.Equal(350000m, dept.Budget);
            Assert.Equal(new DateTime(2007, 9, 1), dept.StartDate);
            Assert.Equal(5, dept.InstructorID);
        }

        [Fact]
        public void Department_InstructorID_IsNullable()
        {
            var dept = new Department { Name = "Test" };
            Assert.Null(dept.InstructorID);
        }

        [Fact]
        public void Department_RowVersion_DefaultsToNull()
        {
            var dept = new Department();
            Assert.Null(dept.RowVersion);
        }
    }

    public class EnrollmentModelTests
    {
        [Fact]
        public void Enrollment_Grade_IsNullable()
        {
            var enrollment = new Enrollment();
            Assert.Null(enrollment.Grade);
        }

        [Fact]
        public void Enrollment_Properties_SetCorrectly()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1050,
                StudentID = 1,
                Grade = Grade.A
            };

            Assert.Equal(1, enrollment.EnrollmentID);
            Assert.Equal(1050, enrollment.CourseID);
            Assert.Equal(1, enrollment.StudentID);
            Assert.Equal(Grade.A, enrollment.Grade);
        }

        [Theory]
        [InlineData(Grade.A)]
        [InlineData(Grade.B)]
        [InlineData(Grade.C)]
        [InlineData(Grade.D)]
        [InlineData(Grade.F)]
        public void Grade_AllValues_AreValid(Grade grade)
        {
            var enrollment = new Enrollment { Grade = grade };
            Assert.Equal(grade, enrollment.Grade);
        }
    }

    public class OfficeAssignmentModelTests
    {
        [Fact]
        public void OfficeAssignment_Properties_SetCorrectly()
        {
            var office = new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Smith 17"
            };

            Assert.Equal(1, office.InstructorID);
            Assert.Equal("Smith 17", office.Location);
        }
    }

    public class CourseAssignmentModelTests
    {
        [Fact]
        public void CourseAssignment_Properties_SetCorrectly()
        {
            var ca = new CourseAssignment
            {
                InstructorID = 1,
                CourseID = 1050
            };

            Assert.Equal(1, ca.InstructorID);
            Assert.Equal(1050, ca.CourseID);
        }
    }

    public class NotificationModelTests
    {
        [Fact]
        public void Notification_Properties_SetCorrectly()
        {
            var now = DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "New student created",
                CreatedAt = now,
                CreatedBy = "admin",
                IsRead = false
            };

            Assert.Equal(1, notification.Id);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("New student created", notification.Message);
            Assert.Equal(now, notification.CreatedAt);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void Notification_ReadAt_IsNullable()
        {
            var notification = new Notification();
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void EntityOperation_HasExpectedValues()
        {
            Assert.Equal(0, (int)EntityOperation.CREATE);
            Assert.Equal(1, (int)EntityOperation.UPDATE);
            Assert.Equal(2, (int)EntityOperation.DELETE);
        }
    }

    public class ErrorViewModelTests
    {
        [Fact]
        public void ShowRequestId_ReturnsFalse_WhenRequestIdIsNull()
        {
            var model = new ErrorViewModel { RequestId = null };
            Assert.False(model.ShowRequestId);
        }

        [Fact]
        public void ShowRequestId_ReturnsFalse_WhenRequestIdIsEmpty()
        {
            var model = new ErrorViewModel { RequestId = "" };
            Assert.False(model.ShowRequestId);
        }

        [Fact]
        public void ShowRequestId_ReturnsTrue_WhenRequestIdHasValue()
        {
            var model = new ErrorViewModel { RequestId = "abc123" };
            Assert.True(model.ShowRequestId);
        }
    }

    public class ViewModelTests
    {
        [Fact]
        public void AssignedCourseData_Properties_SetCorrectly()
        {
            var data = new SchoolViewModels.AssignedCourseData
            {
                CourseID = 1050,
                Title = "Chemistry",
                Assigned = true
            };

            Assert.Equal(1050, data.CourseID);
            Assert.Equal("Chemistry", data.Title);
            Assert.True(data.Assigned);
        }

        [Fact]
        public void EnrollmentDateGroup_Properties_SetCorrectly()
        {
            var date = new DateTime(2020, 9, 1);
            var group = new SchoolViewModels.EnrollmentDateGroup
            {
                EnrollmentDate = date,
                StudentCount = 5
            };

            Assert.Equal(date, group.EnrollmentDate);
            Assert.Equal(5, group.StudentCount);
        }

        [Fact]
        public void EnrollmentDateGroup_EnrollmentDate_IsNullable()
        {
            var group = new SchoolViewModels.EnrollmentDateGroup();
            Assert.Null(group.EnrollmentDate);
        }

        [Fact]
        public void InstructorIndexData_Properties_DefaultToNull()
        {
            var data = new SchoolViewModels.InstructorIndexData();
            Assert.Null(data.Instructors);
            Assert.Null(data.Courses);
            Assert.Null(data.Enrollments);
        }
    }
}

