using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestHelpers.CreateSeededContext();
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        // --- Index ---

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index(null, null, null, null);
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Index_ReturnsPaginatedList()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;
            Assert.IsType<PaginatedList<Student>>(result!.Model);
        }

        [Fact]
        public void Index_ReturnsAllStudents()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            Assert.Equal(3, model!.Count);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            var names = model!.Select(s => s.LastName).ToList();
            Assert.Equal(names.OrderBy(n => n).ToList(), names);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            var names = model!.Select(s => s.LastName).ToList();
            Assert.Equal(names.OrderByDescending(n => n).ToList(), names);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            var dates = model!.Select(s => s.EnrollmentDate).ToList();
            Assert.Equal(dates.OrderBy(d => d).ToList(), dates);
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            var dates = model!.Select(s => s.EnrollmentDate).ToList();
            Assert.Equal(dates.OrderByDescending(d => d).ToList(), dates);
        }

        [Fact]
        public void Index_SearchString_FiltersResults()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            Assert.Single(model!);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_SearchString_FiltersByFirstName()
        {
            var result = _controller.Index(null, null, "Meredith", null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            Assert.Single(model!);
            Assert.Equal("Meredith", model.First().FirstMidName);
        }

        [Fact]
        public void Index_SearchString_ResetsPage()
        {
            var result = _controller.Index(null, null, "A", 3) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            Assert.Equal(1, model!.PageIndex);
        }

        [Fact]
        public void Index_NoSearchString_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Alexander", null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            Assert.Single(model!);
        }

        [Fact]
        public void Index_SetsViewBagCurrentSort()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            Assert.Equal("name_desc", _controller.ViewBag.CurrentSort);
        }

        [Fact]
        public void Index_SetsViewBagNameSortParm()
        {
            // When sortOrder is null/empty, NameSortParm should be "name_desc"
            _controller.Index(null, null, null, null);
            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);

            // When sortOrder is "name_desc", NameSortParm should be ""
            _controller.Index("name_desc", null, null, null);
            Assert.Equal("", _controller.ViewBag.NameSortParm);
        }

        [Fact]
        public void Index_SetsViewBagDateSortParm()
        {
            _controller.Index(null, null, null, null);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);

            _controller.Index("Date", null, null, null);
            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        }

        // --- Details ---

        [Fact]
        public void Details_ReturnsNotFound_WhenIdIsNull()
        {
            var result = _controller.Details(null);
            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithStudent()
        {
            var student = _context.Students.First();
            var result = _controller.Details(student.ID) as ViewResult;
            Assert.NotNull(result);
            var model = result.Model as Student;
            Assert.Equal(student.ID, model!.ID);
        }

        [Fact]
        public void Details_IncludesEnrollments()
        {
            var student = _context.Students.First(s => s.LastName == "Alexander");
            var result = _controller.Details(student.ID) as ViewResult;
            var model = result!.Model as Student;
            Assert.NotNull(model!.Enrollments);
            Assert.NotEmpty(model.Enrollments);
        }

        // --- Create GET ---

        [Fact]
        public void Create_Get_ReturnsViewResult_WithStudent()
        {
            var result = _controller.Create() as ViewResult;
            Assert.NotNull(result);
            var model = result.Model as Student;
            Assert.NotNull(model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        // --- Create POST ---

        [Fact]
        public void Create_Post_ValidModel_RedirectsToIndex()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "User",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            var result = _controller.Create(student);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidModel_SavesStudent()
        {
            var student = new Student
            {
                FirstMidName = "New",
                LastName = "Student",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            _controller.Create(student);
            Assert.True(_context.Students.Any(s => s.LastName == "Student"));
        }

        [Fact]
        public void Create_Post_InvalidDate_MinValue_ReturnsView()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "User",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student);
            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Student>(viewResult.Model);
        }

        [Fact]
        public void Create_Post_InvalidDate_TooOld_ReturnsView()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "User",
                EnrollmentDate = new DateTime(1000, 1, 1)
            };

            var result = _controller.Create(student);
            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Student>(viewResult.Model);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            var result = _controller.Create(student);
            Assert.IsType<ViewResult>(result);
        }

        // --- Edit GET ---

        [Fact]
        public void Edit_Get_ReturnsNotFound_WhenIdIsNull()
        {
            var result = _controller.Edit(null);
            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsNotFound_WhenStudentNotFound()
        {
            var result = _controller.Edit(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ReturnsViewResult_WithStudent()
        {
            var student = _context.Students.First();
            var result = _controller.Edit(student.ID) as ViewResult;
            Assert.NotNull(result);
            var model = result.Model as Student;
            Assert.Equal(student.ID, model!.ID);
        }

        // --- Edit POST ---

        [Fact]
        public void Edit_Post_ValidModel_RedirectsToIndex()
        {
            var student = _context.Students.AsNoTracking().First();
            student.FirstMidName = "Updated";

            var result = _controller.Edit(student);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_ValidModel_UpdatesStudent()
        {
            var student = _context.Students.AsNoTracking().First();
            student.FirstMidName = "Updated";

            _controller.Edit(student);

            var updated = _context.Students.Find(student.ID);
            Assert.Equal("Updated", updated!.FirstMidName);
        }

        [Fact]
        public void Edit_Post_InvalidDate_ReturnsView()
