using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.IO;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _tempDir;

        public CoursesControllerTests()
        {
            _context = TestHelpers.CreateSeededContext();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockLogger = new Mock<ILogger<CoursesController>>();
            _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempDir);
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);
            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempDir))
            {
                try { Directory.Delete(_tempDir, true); } catch { }
            }
        }

        // --- Index ---

        [Fact]
        public void Index_ReturnsViewResult_WithCourses()
        {
            var result = _controller.Index() as ViewResult;
            Assert.NotNull(result);
            var model = result.Model as System.Collections.Generic.List<Course>;
            Assert.NotNull(model);
            Assert.Equal(2, model.Count);
        }

        // --- Details ---

        [Fact]
        public void Details_ReturnsNotFound_WhenIdIsNull()
        {
            var result = _controller.Details(null);
            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithCourse()
        {
            var course = _context.Courses.First();
            var result = _controller.Details(course.CourseID) as ViewResult;
            Assert.NotNull(result);
            var model = result.Model as Course;
            Assert.Equal(course.CourseID, model!.CourseID);
        }

        // --- Create GET ---

        [Fact]
        public void Create_Get_ReturnsViewResult_WithNewCourse()
        {
            var result = _controller.Create() as ViewResult;
            Assert.NotNull(result);
            Assert.IsType<Course>(result.Model);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        // --- Create POST ---

        [Fact]
        public void Create_Post_ValidModel_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 3,
                DepartmentID = _context.Departments.First().DepartmentID
            };

            var result = _controller.Create(course, null!);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidModel_SavesCourse()
        {
            var course = new Course
            {
                CourseID = 8888,
                Title = "Saved Course",
                Credits = 4,
                DepartmentID = _context.Departments.First().DepartmentID
            };

            _controller.Create(course, null!);
            Assert.NotNull(_context.Courses.Find(8888));
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 7777 };

            var result = _controller.Create(course, null!) as ViewResult;
            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_Post_WithValidImage_SavesFile()
        {
            var course = new Course
            {
                CourseID = 6666,
                Title = "With Image",
                Credits = 3,
                DepartmentID = _context.Departments.First().DepartmentID
            };

            var mockFile = CreateMockFormFile("test.jpg", 100, "image/jpeg");

            var result = _controller.Create(course, mockFile.Object);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);

            var savedCourse = _context.Courses.Find(6666);
            Assert.NotNull(savedCourse!.TeachingMaterialImagePath);
            Assert.Contains("/Uploads/TeachingMaterials/", savedCourse.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_Post_WithInvalidExtension_ReturnsView()
        {
            var course = new Course
            {
                CourseID = 5555,
                Title = "Bad Extension",
                Credits = 3,
                DepartmentID = _context.Departments.First().DepartmentID
            };

            var mockFile = CreateMockFormFile("test.exe", 100, "application/octet-stream");

            var result = _controller.Create(course, mockFile.Object) as ViewResult;
            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_WithOversizedImage_ReturnsView()
        {
            var course = new Course
            {
                CourseID = 4444,
                Title = "Too Big",
                Credits = 3,
                DepartmentID = _context.Departments.First().DepartmentID
            };

            var mockFile = CreateMockFormFile("test.jpg", 6 * 1024 * 1024, "image/jpeg");

            var result = _controller.Create(course, mockFile.Object) as ViewResult;
            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        // --- Edit GET ---

        [Fact]
        public void Edit_Get_ReturnsNotFound_WhenIdIsNull()
        {
            var result = _controller.Edit(null);
            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsNotFound_WhenCourseNotFound()
        {
            var result = _controller.Edit(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ReturnsViewResult_WithCourse()
        {
            var course = _context.Courses.First();
            var result = _controller.Edit(course.CourseID) as ViewResult;
            Assert.NotNull(result);
            var model = result.Model as Course;
            Assert.Equal(course.CourseID, model!.CourseID);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        // --- Edit POST ---

        [Fact]
        public void Edit_Post_ValidModel_RedirectsToIndex()
        {
            var course = _context.Courses.AsNoTracking().First();
            course.Title = "Updated Title";

            var result = _controller.Edit(course, null!);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_ValidModel_UpdatesCourse()
        {
            var course = _context.Courses.AsNoTracking().First();
            course.Title = "Updated Title";

            _controller.Edit(course, null!);

            var updated = _context.Courses.Find(course.CourseID);
            Assert.Equal("Updated Title", updated!.Title);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = _context.Courses.AsNoTracking().First();

            var result = _controller.Edit(course, null!) as ViewResult;
            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Edit_Post_WithInvalidExtension_ReturnsView()
        {
            var course = _context.Courses.AsNoTracking().First();
            var mockFile = CreateMockFormFile("test.pdf", 100, "application/pdf");

            var result = _controller.Edit(course, mockFile.Object) as ViewResult;
            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Edit_Post_WithOversizedFile_ReturnsView()
        {
            var course = _context.Courses.AsNoTracking().First();
            var mockFile = CreateMockFormFile("test.png", 6 * 1024 * 1024, "image/png");

            var result = _controller.Edit(course, mockFile.Object) as ViewResult;
            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Edit_Post_WithValidImage_UpdatesPath()
        {
            var course = _context.Courses.AsNoTracking().First();
            var mockFile = CreateMockFormFile("updated.png", 100, "image/png");

            var result = _controller.Edit(course, mockFile.Object);
            Assert.IsType<RedirectToActionResult>(result);

            var updated = _context.Courses.Find(course.CourseID);
            Assert.NotNull(updated!.TeachingMaterialImagePath);
            Assert.Contains("/Uploads/TeachingMaterials/", updated.TeachingMaterialImagePath);
        }

        // --- Delete GET ---

        [Fact]
        public void Delete_Get_ReturnsNotFound_WhenIdIsNull()
        {
            var result = _controller.Delete(null);
            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsViewResult_WithCourse()
        {
            var course = _context.Courses.First();
            var result = _controller.Delete(course.CourseID) as ViewResult;
            Assert.NotNull(result);
            var model = result.Model as Course;
            Assert.Equal(course.CourseID, model!.CourseID);
        }

        // --- DeleteConfirmed ---

        [Fact]
        public void DeleteConfirmed_RedirectsToIndex()
        {
            var course = _context.Courses.First();
            var result = _controller.DeleteConfirmed(course.CourseID);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void DeleteConfirmed_RemovesCourse()
        {
            var course = _context.Courses.First();
            var id = course.CourseID;
            _controller.DeleteConfirmed(id);
            Assert.Null(_context.Courses.Find(id));
        }

        // --- Helpers ---

        private static Mock<IFormFile> CreateMockFormFile(string fileName, long length, string contentType)
        {
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns(fileName);
            mockFile.Setup(f => f.Length).Returns(length);
            mockFile.Setup(f => f.ContentType).Returns(contentType);
            var stream = new MemoryStream(new byte[Math.Min(length, 1024)]);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s =>
            {
                stream.CopyTo(s);
            });
            return mockFile;
        }
    }
}

