using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestHelpers.CreateSeededContext();
            _controller = new DepartmentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        // --- Index ---

        [Fact]
        public void Index_ReturnsViewResult_WithDepartments()
        {
            var result = _controller.Index() as ViewResult;
            Assert.NotNull(result);
            var model = result.Model as System.Collections.Generic.List<Department>;
            Assert.NotNull(model);
            Assert.Equal(2, model.Count);
        }

        // --- Details ---

        [Fact]
        public void Details_ReturnsNotFound_WhenIdIsNull()
        {
            var result = _controller.Details(null);
            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenDepartmentNotFound()
        {
            var result = _controller.Details(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithDepartment()
        {
            var dept = _context.Departments.First();
            var result = _controller.Details(dept.DepartmentID) as ViewResult;
            Assert.NotNull(result);
            var model = result.Model as Department;
            Assert.Equal(dept.DepartmentID, model!.DepartmentID);
        }

        // --- Create GET ---

        [Fact]
        public void Create_Get_ReturnsViewResult()
        {
            var result = _controller.Create() as ViewResult;
            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // --- Create POST ---

        [Fact]
        public void Create_Post_ValidModel_RedirectsToIndex()
        {
            var dept = new Department
            {
                Name = "Science",
                Budget = 200000,
                StartDate = new DateTime(2020, 9, 1),
                InstructorID = _context.Instructors.First().ID
            };

            var result = _controller.Create(dept);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidModel_SavesDepartment()
        {
            var dept = new Department
            {
                Name = "Science",
                Budget = 200000,
                StartDate = new DateTime(2020, 9, 1),
                InstructorID = _context.Instructors.First().ID
            };

            _controller.Create(dept);
            Assert.True(_context.Departments.Any(d => d.Name == "Science"));
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department();

            var result = _controller.Create(dept) as ViewResult;
            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // --- Edit GET ---

        [Fact]
        public void Edit_Get_ReturnsNotFound_WhenIdIsNull()
        {
            var result = _controller.Edit(null);
            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsNotFound_WhenDepartmentNotFound()
        {
            var result = _controller.Edit(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ReturnsViewResult_WithDepartment()
        {
            var dept = _context.Departments.First();
            var result = _controller.Edit(dept.DepartmentID) as ViewResult;
            Assert.NotNull(result);
            var model = result.Model as Department;
            Assert.Equal(dept.DepartmentID, model!.DepartmentID);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // --- Edit POST ---

        [Fact]
        public void Edit_Post_ValidModel_RedirectsToIndex()
        {
            var dept = _context.Departments.AsNoTracking().First();
            dept.Name = "Updated Dept";

            var result = _controller.Edit(dept);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_ValidModel_UpdatesDepartment()
        {
            var dept = _context.Departments.AsNoTracking().First();
            dept.Name = "Updated Dept";

            _controller.Edit(dept);

            var updated = _context.Departments.Find(dept.DepartmentID);
            Assert.Equal("Updated Dept", updated!.Name);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = _context.Departments.AsNoTracking().First();

            var result = _controller.Edit(dept) as ViewResult;
            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // --- Delete GET ---

        [Fact]
        public void Delete_Get_ReturnsNotFound_WhenIdIsNull()
        {
            var result = _controller.Delete(null);
            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsNotFound_WhenDepartmentNotFound()
        {
            var result = _controller.Delete(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ReturnsViewResult_WithDepartment()
        {
            var dept = _context.Departments.First();
            var result = _controller.Delete(dept.DepartmentID) as ViewResult;
            Assert.NotNull(result);
            var model = result.Model as Department;
            Assert.Equal(dept.DepartmentID, model!.DepartmentID);
        }

        // --- DeleteConfirmed ---

        [Fact]
        public void DeleteConfirmed_RedirectsToIndex()
        {
            var dept = _context.Departments.First();
            var result = _controller.DeleteConfirmed(dept.DepartmentID);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void DeleteConfirmed_RemovesDepartment()
        {
            var dept = _context.Departments.First();
            var id = dept.DepartmentID;
            _controller.DeleteConfirmed(id);
            Assert.Null(_context.Departments.Find(id));
        }
    }
}

