using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestHelpers.CreateSeededContext();
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        // --- Index ---

        [Fact]
        public void Index_ReturnsViewResult_WithInstructorIndexData()
        {
            var result = _controller.Index(null, null) as ViewResult;
            Assert.NotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.NotNull(model);
            Assert.NotNull(model.Instructors);
        }

        [Fact]
        public void Index_ReturnsAllInstructors()
        {
            var result = _controller.Index(null, null) as ViewResult;
            var model = result!.Model as InstructorIndexData;
            Assert.Equal(2, model!.Instructors.Count());
        }

        [Fact]
        public void Index_OrdersByLastName()
        {
            var result = _controller.Index(null, null) as ViewResult;
            var model = result!.Model as InstructorIndexData;
            var names = model!.Instructors.Select(i => i.LastName).ToList();
            Assert.Equal(names.OrderBy(n => n).ToList(), names);
        }

        [Fact]
        public void Index_WithInstructorId_SetsCourses()
        {
            var instructor = _context.Instructors.First(i => i.LastName == "Abercrombie");
            var result = _controller.Index(instructor.ID, null) as ViewResult;
            var model = result!.Model as InstructorIndexData;
            Assert.NotNull(model!.Courses);
            Assert.NotEmpty(model.Courses);
        }

        [Fact]
        public void Index_WithInstructorId_SetsViewBag()
        {
            var instructor = _context.Instructors.First();
            _controller.Index(instructor.ID, null);
            Assert.Equal(instructor.ID, (int)_controller.ViewBag.InstructorID);
        }

        // --- Details ---

        [Fact]
        public void Details_ReturnsNotFound_WhenIdIsNull()
        {
            var result = _controller.Details(null);
            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenInstructorNotFound()
        {
            var result = _controller.Details(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithInstructor()
        {
            var instructor = _context.Instructors.First();
            var result = _controller.Details(instructor.ID) as ViewResult;
            Assert.NotNull(result);
            var model = result.Model as Instructor;
            Assert.Equal(instructor.ID, model!.ID);
        }

        // --- Create GET ---

        [Fact]
        public void Create_Get_ReturnsViewResult_WithInstructor()
        {
            var result = _controller.Create() as ViewResult;
            Assert.NotNull(result);
            var model = result.Model as Instructor;
            Assert.NotNull(model);
            Assert.NotNull(model.CourseAssignments);
            Assert.Empty(model.CourseAssignments);
        }

        [Fact]
        public void Create_Get_PopulatesAssignedCourseData()
        {
            _controller.Create();
            var courses = _controller.ViewBag.Courses as List<AssignedCourseData>;
            Assert.NotNull(courses);
            Assert.Equal(_context.Courses.Count(), courses.Count);
        }

        // --- Create POST ---

        [Fact]
        public void Create_Post_ValidModel_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Teacher",
                HireDate = new DateTime(2020, 1, 15)
            };

            var result = _controller.Create(instructor, null!);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidModel_SavesInstructor()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Teacher",
                HireDate = new DateTime(2020, 1, 15)
            };

            _controller.Create(instructor, null!);
            Assert.True(_context.Instructors.Any(i => i.LastName == "Teacher"));
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_CreatesCourseAssignments()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "WithCourses",
                HireDate = new DateTime(2020, 1, 15)
            };
            var courseIds = _context.Courses.Select(c => c.CourseID.ToString()).ToArray();

            _controller.Create(instructor, courseIds);

            var saved = _context.Instructors
                .Include(i => i.CourseAssignments)
                .First(i => i.LastName == "WithCourses");
            Assert.Equal(courseIds.Length, saved.CourseAssignments.Count);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor { HireDate = DateTime.Today };

            var result = _controller.Create(instructor, null!) as ViewResult;
            Assert.NotNull(result);
        }

        // --- Delete GET ---

        [Fact]
        public void Delete_Get_ReturnsNotFound_WhenIdIsNull()
        {
            var result = _controller.Delete(null);
            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsNotFound_WhenInstructorNotFound()
        {
            var result = _controller.Delete(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ReturnsViewResult_WithInstructor()
        {
            var instructor = _context.Instructors.First();
            var result = _controller.Delete(instructor.ID) as ViewResult;
            Assert.NotNull(result);
            var model = result.Model as Instructor;
            Assert.Equal(instructor.ID, model!.ID);
        }

        // --- DeleteConfirmed ---

        [Fact]
        public void DeleteConfirmed_RedirectsToIndex()
        {
            // Use instructor without office assignment
            var instructor = _context.Instructors.First(i => i.LastName == "Abercrombie");
            var result = _controller.DeleteConfirmed(instructor.ID);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void DeleteConfirmed_RemovesInstructor()
        {
            var instructor = _context.Instructors.First(i => i.LastName == "Abercrombie");
            var id = instructor.ID;
            _controller.DeleteConfirmed(id);
            Assert.Null(_context.Instructors.Find(id));
        }

        [Fact]
        public void DeleteConfirmed_ClearsDepartmentAdministrator()
        {
            var instructor = _context.Instructors.First(i => i.LastName == "Abercrombie");
            var dept = _context.Departments.First(d => d.InstructorID == instructor.ID);

            _controller.DeleteConfirmed(instructor.ID);

            var updatedDept = _context.Departments.Find(dept.DepartmentID);
            Assert.Null(updatedDept!.InstructorID);
        }
    }
}

