using ContosoUniversity.Data;
using ContosoUniversity.Tests.Helpers;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Data
{
    public class DbInitializerTests
    {
        [Fact]
        public void Initialize_SeedsStudents()
        {
            var context = TestHelpers.CreateContext();
            DbInitializer.Initialize(context);
            Assert.Equal(8, context.Students.Count());
            context.Dispose();
        }

        [Fact]
        public void Initialize_SeedsInstructors()
        {
            var context = TestHelpers.CreateContext();
            DbInitializer.Initialize(context);
            Assert.Equal(5, context.Instructors.Count());
            context.Dispose();
        }

        [Fact]
        public void Initialize_SeedsDepartments()
        {
            var context = TestHelpers.CreateContext();
            DbInitializer.Initialize(context);
            Assert.Equal(4, context.Departments.Count());
            context.Dispose();
        }

        [Fact]
        public void Initialize_SeedsCourses()
        {
            var context = TestHelpers.CreateContext();
            DbInitializer.Initialize(context);
            Assert.Equal(7, context.Courses.Count());
            context.Dispose();
        }

        [Fact]
        public void Initialize_SeedsEnrollments()
        {
            var context = TestHelpers.CreateContext();
            DbInitializer.Initialize(context);
            Assert.Equal(11, context.Enrollments.Count());
            context.Dispose();
        }

        [Fact]
        public void Initialize_SeedsOfficeAssignments()
        {
            var context = TestHelpers.CreateContext();
            DbInitializer.Initialize(context);
            Assert.Equal(3, context.OfficeAssignments.Count());
            context.Dispose();
        }

        [Fact]
        public void Initialize_SeedsCourseAssignments()
        {
            var context = TestHelpers.CreateContext();
            DbInitializer.Initialize(context);
            Assert.Equal(8, context.CourseAssignments.Count());
            context.Dispose();
        }

        [Fact]
        public void Initialize_SkipsIfAlreadySeeded()
        {
            var dbName = Guid.NewGuid().ToString();
            var context1 = TestHelpers.CreateContext(dbName);
            DbInitializer.Initialize(context1);

            var context2 = TestHelpers.CreateContext(dbName);
            DbInitializer.Initialize(context2);

            // Should still have same counts
            Assert.Equal(8, context2.Students.Count());
            Assert.Equal(5, context2.Instructors.Count());

            context1.Dispose();
            context2.Dispose();
        }

        [Fact]
        public void Initialize_DepartmentsHaveAdministrators()
        {
            var context = TestHelpers.CreateContext();
            DbInitializer.Initialize(context);
            var depts = context.Departments.ToList();
            Assert.All(depts, d => Assert.NotNull(d.InstructorID));
            context.Dispose();
        }

        [Fact]
        public void Initialize_CoursesHaveDepartments()
        {
            var context = TestHelpers.CreateContext();
            DbInitializer.Initialize(context);
            var courses = context.Courses.ToList();
            Assert.All(courses, c => Assert.NotEqual(0, c.DepartmentID));
            context.Dispose();
        }
    }

    public class SchoolContextTests
    {
        [Fact]
        public void SchoolContext_CanBeCreatedWithInMemoryProvider()
        {
            var context = TestHelpers.CreateContext();
            Assert.NotNull(context);
            context.Dispose();
        }

        [Fact]
        public void SchoolContext_HasAllDbSets()
        {
            var context = TestHelpers.CreateContext();
            Assert.NotNull(context.Courses);
            Assert.NotNull(context.Enrollments);
            Assert.NotNull(context.Departments);
            Assert.NotNull(context.OfficeAssignments);
            Assert.NotNull(context.CourseAssignments);
            Assert.NotNull(context.People);
            Assert.NotNull(context.Students);
            Assert.NotNull(context.Instructors);
            Assert.NotNull(context.Notifications);
            context.Dispose();
        }

        [Fact]
        public void SchoolContext_CanAddAndRetrieveStudent()
        {
            var context = TestHelpers.CreateContext();
            var student = new ContosoUniversity.Models.Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Today
            };
            context.Students.Add(student);
            context.SaveChanges();

            var retrieved = context.Students.First();
            Assert.Equal("Test", retrieved.FirstMidName);
            Assert.Equal("Student", retrieved.LastName);
            context.Dispose();
        }

        [Fact]
        public void SchoolContext_CourseAssignment_HasCompositeKey()
        {
            var context = TestHelpers.CreateSeededContext();
            var ca = context.CourseAssignments.First();
            Assert.NotEqual(0, ca.CourseID);
            Assert.NotEqual(0, ca.InstructorID);
            context.Dispose();
        }
    }
}

