public void Edit_Post_ValidModel_RedirectsToIndex()
{
    _context.ChangeTracker.Clear();
    var dept = _context.Departments.AsNoTracking().First();
    dept.Name = "Updated Dept";

    var result = _controller.Edit((Department)dept);
    var redirect = Assert.IsType<RedirectToActionResult>(result);
    Assert.Equal("Index", redirect.ActionName);
}

[Fact]
public void Edit_Post_ValidModel_UpdatesDepartment()
{
    var dept = _context.Departments.AsNoTracking().First();
    dept.Name = "Updated Dept";

    _controller.Edit((Department)dept);

    var updated = _context.Departments.Find(dept.DepartmentID);
    Assert.Equal("Updated Dept", updated!.Name);
}

